form:Form.form:Scripts:
		var qrylist = "SELECT TTA10_LIQUIDACPERS.oi_personal_emp as ID, PER02_PERSONAL_EMP.e_numero_legajo as LEGAJO, ORG03_EMPRESAS.c_empresa AS EMPRESA, PER01_PERSONAL.d_ape_y_nom AS APE_Y_NOM FROM  TTA10_LIQUIDACPERS, PER02_PERSONAL_EMP, ORG03_EMPRESAS, PER01_PERSONAL JOIN TTA10_LIQUIDACPERS.oi_personal_emp INNER PER02_PERSONAL_EMP.oi_personal_emp, ORG03_EMPRESAS.oi_empresa INNER PER02_PERSONAL_EMP.oi_empresa, PER01_PERSONAL.oi_personal INNER PER02_PERSONAL_EMP.oi_personal WHERE TTA10_LIQUIDACPERS.oi_liquidacion = {PARAM}";
var fileData;
var rowEdited = new Array();
var gID;

function ONLOAD()
{	
	internal_filter();

	if (Ctrl('c_estado').GetCValue() == "ini") 
	{  
		CtrlEnabled('VAL_VAR', true);
		CtrlEnabled('PROC_PER', true);
	}

	if (Ctrl('c_estado').GetCValue() == "pro") 
	{  
		CtrlEnabled('VAL_VAR', true);
		CtrlEnabled('PROC_PER', true);
	}  

	if (Ctrl('c_estado').GetCValue() == "cer") 
	{ 		
		CtrlEnabled('VAL_VAR', false);
		CtrlEnabled('PROC_PER', false);
	}

	if (Ctrl('c_estado').GetCValue() == "con") 
	{ 		
		CtrlEnabled('PROC', false);
		CtrlEnabled('SAVE', false);
	}
}

function filter()  
{ 	
	Ctrl("listFILTER").SetXValue("");
	NomadTimeout("internal_filter();",100,"Filtrando la Lista...");
}

function internal_filter()
{	
	var qryfilter = Replace(qrylist, "{PARAM}", Ctrl("id").GetXValue());
	if(Ctrl("iter_search").GetXValue() != "")
	{
		qryfilter += " AND (contain(ucase(PER01_PERSONAL.d_ape_y_nom), \\'{VALUE}\\') OR contain(ucase(PER02_PERSONAL_EMP.e_numero_legajo), \\'{VALUE}\\') OR contain(ucase(ORG03_EMPRESAS.c_empresa), \\'{VALUE}\\'))";
		qryfilter = Replace(qryfilter, "{VALUE}", Ctrl("iter_search").GetXValue().toUpperCase());	
	}

	qryfilter += " ORDER BY LEGAJO ASC";
	Ctrl("listFILTER").SQL = qryfilter;		
	Ctrl("listFILTER").ResetSQL();

	SetGrid();	
}


function VAL_VAR()
{	
	if(Ctrl('listFILTER').GetXValue() != "")
	{
		var param = "<DATA oi_liquidacion=\"" + Ctrl("id").GetXValue() + "\" oi_personal_emp=\"" +Ctrl('listFILTER').GetXValue()+ "\"/>";	
		openNewFlowWait('NucleusRH.Base.Tiempos_Trabajados.Liquidacion_Personas.VAL_VAR.flow','VAL_VAR',param,new ObjectResult(), "L");			
	}
	else
	{
		alert("No ha seleccionado ningún legajo");
		return false;
	}
}

function CONC_VAL()
{	
	if(Ctrl('listFILTER').GetXValue() != "")
	{		
		if (IsEdited())
		{			
			if (confirm('Desea continuar sin guardar los cambios realizados?'))
			{
				var param = "<DATA oi_liquidacion=\"" + Ctrl("id").GetXValue() + "\" oi_personal_emp=\"" +Ctrl('listFILTER').GetXValue()+ "\"/>";	
				openNewFlowWait('NucleusRH.Base.Tiempos_Trabajados.Liquidacion_Personas.CONC_VAL.flow','REPORT',param,new ObjectResult(), "L");			
			}
			else
				return false;
		}
		else
		{
			var param = "<DATA oi_liquidacion=\"" + Ctrl("id").GetXValue() + "\" oi_personal_emp=\"" +Ctrl('listFILTER').GetXValue()+ "\"/>";	
			openNewFlowWait('NucleusRH.Base.Tiempos_Trabajados.Liquidacion_Personas.CONC_VAL.flow','REPORT',param,new ObjectResult(), "L");			
		}			
	}
	else
	{
		alert("No ha seleccionado ningún legajo");
		return false;
	}
	return true;
}

function Procesar()
{	
	if(Ctrl('listFILTER').GetXValue() != "")
	{
		var param = new NomadXML("DATA"); 
		param.SetAttr("oi_liquidacion", Ctrl('id').GetXValue());
		param.SetAttr("oi_personal_emp", Ctrl('listFILTER').GetXValue());
		param.SetAttr("idrep", Ctrl('idrep').GetXValue());

		openNewFlow('NucleusRH.Base.Tiempos_Trabajados.Liquidacion.flow','PROC_PER',param.ToString(),new ObjectResult2(), "L");
	}
	else
	{
		alert("No ha seleccionado ningún legajo");
		return false;
	}
}

function SetGrid()
{
	if(Ctrl('listFILTER').GetXValue() != "")
	{
		Ctrl("PAGINA_INTERFAZ").SetURL("");				
		fileData = GetProxy().FileServiceIO().LoadFileXML("TEMP", "Procesamiento-"+Ctrl('idrep').GetXValue()+".xml");				
		rowEdited = new Array();
		gID = Ctrl('listFILTER').GetXValue(); 
		Ctrl("PAGINA_INTERFAZ").SetURL("../../../ReportViewer.aspx?ut="+GetProxy().UserToken()+"&empty=0&file=NucleusRH.Base.Tiempos_Trabajados.HorasManual.rpt&idrep="+Ctrl('idrep').GetXValue()+"&now="+(new Date()).toString());
	}
	else
	{		
		Ctrl("PAGINA_INTERFAZ").SetURL("../../../ReportViewer.aspx?ut="+GetProxy().UserToken()+"&empty=1&file=NucleusRH.Base.Tiempos_Trabajados.HorasManual.rpt&now="+(new Date()).toString());
	}
}


function OnLostFocusValor(obj, value)
{
	var jor = obj.id.split("_")[1];
	var con = obj.id.split("_")[2];

	if (jor!="0")
	{				
		var det = fileData.FindElement("DETALLE").FindElement2("DET", "fec", jor);		
		det.SetAttr("conc_"+con, value);
	}
	else
	{

		var men = fileData.FindElement("MENSUAL").FindElement2("CONMEN", "oi_concepto", con);		
		men.SetAttr("cant", value);
	}
}

function SetChg(obj)
{
	var jor = obj.id.split("_")[1];
	var con = obj.id.split("_")[2];

	if (jor!="0")
	{				
		var det = fileData.FindElement("DETALLE").FindElement2("DET", "fec", jor);				

		if(det.GetAttr("chg")!="")
		{			
			if(det.GetAttr("chg").indexOf(",conc_"+con+",") == -1)
				det.SetAttr("chg", det.GetAttr("chg") + "conc_"+con+",");
		}
		else
			det.SetAttr("chg", ",conc_"+con+",");
	}
	else
	{		
		var men = fileData.FindElement("MENSUAL").FindElement2("CONMEN", "oi_concepto", con);				

		if(men.GetAttr("chg")!="")
		{
		 	if(men.GetAttr("chg").indexOf(",conc_"+con+",") == -1)
				men.SetAttr("chg", men.GetAttr("chg") + "conc_"+con+",");
		}
		else
			men.SetAttr("chg", ",conc_"+con+",");
	}
}

function UnSetChg()
{							
	for(var xmldet = fileData.FindElement("DETALLE").FirstChild(); xmldet!=null;xmldet=xmldet.Next())
		xmldet.SetAttr("chg", "");		

	for(var xmlmen = fileData.FindElement("MENSUAL").FirstChild(); xmlmen!=null;xmlmen=xmlmen.Next())
		xmlmen.SetAttr("chg", "");
}

function SetTotal(con)
{		
	var tot=0;
	for(var xmldet = fileData.FindElement("DETALLE").FirstChild(); xmldet!=null;xmldet=xmldet.Next())
	{		
		var val = xmldet.GetAttr("conc_"+con);
		tot+=toDecimal(val);		
	}			
	return tot;
}

function toDecimal(val)
{
	if(val=="")
		return 0;	

	if(validateDouble(val))
		return parseFloat(val);

	var hh = parseInt(val.split(":")[0],10);
	var mm = parseInt(val.split(":")[1],10);

	return roundNumber(hh+(mm/60),2);
}

function toTime(val)
{
	if (validateHhMm(val))
		return val;
	var ent = Math.floor(val);
	var dec = roundNumber((val - ent) * 60,0);

	if(dec < 10)
		dec = "0"+dec;
	return ent+":"+dec;	
}

function internal_clicklist()
{
	if (IsEdited())
	{
		if (!confirm('Desea continuar sin guardar los cambios realizados?'))
		{
			UnSetChg();
			Ctrl("listFILTER").SetXValue(gID);
			return false;
		}
	}	

	if (Ctrl('listFILTER').GetXValue() != "")
	{
		var param = new NomadXML("DATA"); 
		param.SetAttr("oi_liquidacion", Ctrl('id').GetXValue());
		param.SetAttr("oi_personal_emp", Ctrl('listFILTER').GetXValue());

		openNewFlow('NucleusRH.Base.Tiempos_Trabajados.Liquidacion.flow','SETREP',param.ToString(),new ObjectResult2(), "L");					
	}	

	return true;
}

function ver_archivo()
{		
	alert(fileData.ToString());
}

function SetEdited(id, value)
{
	rowEdited[id] = value;
}

function IsEdited()
{		
	for(var x in rowEdited)
	{						
		if(rowEdited[x])		
			return true;
	}	
	return false;
}

function internal_save()
{
	if(Ctrl('listFILTER').GetXValue() != "")
	{
		GetProxy().FileServiceIO().SaveFile("TEMP","Procesamiento-" + Ctrl('idrep').GetXValue() + ".xml", fileData.ToString());	
		var param = new NomadXML("DATA"); 
		param.SetAttr("oi_liquidacion", Ctrl('id').GetXValue());
		param.SetAttr("oi_personal_emp", Ctrl('listFILTER').GetXValue());
		param.SetAttr("idrep", Ctrl('idrep').GetXValue());

		openNewFlow('NucleusRH.Base.Tiempos_Trabajados.Liquidacion.flow','SAVE',param.ToString(),new ObjectResult2(), "L");		
	}
	else
	{
		alert("No ha seleccionado ningún legajo");
		return false;
	}
}


function Volver()
{
	if(Ctrl('listFILTER').GetXValue() != "")
	{
		if (IsEdited())
		{
			if (confirm('Desea salir sin guardar los cambios?'))
			{
				UnSetChg();
				Ctrl('main').DoEvent("BackForm");	
				return true;
			}
			else
				return false
		}
		else
		{
			UnSetChg();
			Ctrl('main').DoEvent("BackForm");				
			return false;
		}	
	}	
	if(fileData!=null)
		UnSetChg();
	Ctrl('main').DoEvent("BackForm");	
	return true;

}


function validateval(inputField, con)
{	
	var con = fileData.FindElement("CON").FindElement2("C", "id", con);	
	if(con.GetAttr("c_unidad")=="horas")
	{
		if(!validateHhMm(inputField.value))
			inputField.value="";	
		return validateHhMm(inputField);
	}
	else
	{
		if(!validateDouble(inputField.value))
			inputField.value="";	
		return validateDouble(inputField);
	}

	return true;			
}


function validateHhMm(value) 
{
	var isValid = /^([0-9]?[0-9]?[0-9]):([0-5][0-9])$/.test(value);	
	return isValid;
}


function validateDouble(value)
{
	if (value.toString().indexOf(':') !=-1)
		return false;

	var pattern = /^\d+.?\d*$/;
 	var str = value.toString().replace(",",".");

	if (str.match(pattern)==null)
		return false;

	return true;
}

function roundNumber(number, decimals) 
{
	var newnumber = new Number(number+'').toFixed(parseInt(decimals,10));
	return parseFloat(newnumber);
}



function Guardar()  
{
	NomadTimeout("internal_save();",100,"Guardando los datos...");
}

function ClickList()  
{
	NomadTimeout("internal_clicklist();",100,"Recuperando información...");
}

function GetUnit(con)
{
	var con = fileData.FindElement("CON").FindElement2("C", "id", con);	
	return con.GetAttr("c_unidad");
}

function ObjectResult()
{
	this.processResult = function()
	{		
	}
}

function ObjectResult2()
{
	this.processResult = function(strin)
	{
		var xmlin = new NomadXML(strin)		
		Ctrl('idrep').SetXValue(xmlin.GetAttr("idrep"));				

		SetGrid();	
	}
}
